item.description:
这是一道比较简单的题目，不涉及反序列化的知识，一个 Jtar 的解析问题
git clone https://github.com/5i1encee/D3CTF2025-d3jtar.git wget -O jdk-8u202-linux-x64.tar.gz https://repo.huaweicloud.com/java/jdk/8u202-b08/jdk-8u202-linux-x64.tar.gz docker build -t d3jtar_image . docker run -d -p 8080:8080 --name d3jtar d3jtar_image 启动容器之后，解压 tar 包开始分析，看下控制器
// // Source code recreated from a .class file by IntelliJ IDEA // (powered by FernFlower decompiler) // package d3.example.controller; import d3.example.utils.BackUp; import d3.example.utils.Upload; import java.io.File; import java.io.IOException; import java.nio.file.Paths; import java.util.Arrays; import java.util.HashSet; import java.util.Objects; import java.util.Set; import javax.servlet.http.HttpServletRequest; import org.springframework.stereotype.Controller; import org.springframework.web.bind.annotation.GetMapping; import org.springframework.web.bind.annotation.PostMapping; import org.springframework.web.bind.annotation.RequestParam; import org.springframework.web.bind.annotation.ResponseBody; import org.springframework.web.multipart.MultipartFile; import org.springframework.web.servlet.ModelAndView; @Controller public class MainController { @GetMapping({&amp;#34;/view&amp;#34;}) public ModelAndView view(@RequestParam String page, HttpServletRequest request) { if (page.matches(&amp;#34;^[a-zA-Z0-9-]+$&amp;#34;)) { String viewPath = &amp;#34;/WEB-INF/views/&amp;#34; + page + &amp;#34;.jsp&amp;#34;; String realPath = request.getServletContext().getRealPath(viewPath); File jspFile = new File(realPath); if (realPath != null &amp;amp;&amp;amp; jspFile.exists()) { return new ModelAndView(page); } } ModelAndView mav = new ModelAndView(&amp;#34;Error&amp;#34;); mav.addObject(&amp;#34;message&amp;#34;, &amp;#34;The file don&amp;#39;t exist.&amp;#34;); return mav; } @PostMapping({&amp;#34;/Upload&amp;#34;}) @ResponseBody public String UploadController(@RequestParam MultipartFile file) { try { String uploadDir = &amp;#34;webapps/ROOT/WEB-INF/views&amp;#34;; Set&amp;lt;String&amp;gt; blackList = new HashSet(Arrays.asList(&amp;#34;jsp&amp;#34;, &amp;#34;jspx&amp;#34;, &amp;#34;jspf&amp;#34;, &amp;#34;jspa&amp;#34;, &amp;#34;jsw&amp;#34;, &amp;#34;jsv&amp;#34;, &amp;#34;jtml&amp;#34;, &amp;#34;jhtml&amp;#34;, &amp;#34;sh&amp;#34;, &amp;#34;xml&amp;#34;, &amp;#34;war&amp;#34;, &amp;#34;jar&amp;#34;)); String filePath = Upload.secureUpload(file, uploadDir, blackList); return &amp;#34;Upload Success: &amp;#34; + filePath; } catch (Upload.UploadException e) { return &amp;#34;The file is forbidden: &amp;#34; + e; } } @PostMapping({&amp;#34;/BackUp&amp;#34;}) @ResponseBody public String BackUpController(@RequestParam String op) { if (Objects.equals(op, &amp;#34;tar&amp;#34;)) { try { BackUp.tarDirectory(Paths.get(&amp;#34;backup.tar&amp;#34;), Paths.get(&amp;#34;webapps/ROOT/WEB-INF/views&amp;#34;)); return &amp;#34;Success !&amp;#34;; } catch (IOException var3) { return &amp;#34;Failure : tar Error&amp;#34;; } } else if (Objects.equals(op, &amp;#34;untar&amp;#34;)) { try { BackUp.untar(Paths.get(&amp;#34;webapps/ROOT/WEB-INF/views&amp;#34;), Paths.get(&amp;#34;backup.tar&amp;#34;)); return &amp;#34;Success !&amp;#34;; } catch (IOException var4) { return &amp;#34;Failure : untar Error&amp;#34;; } } else { return &amp;#34;Failure : option Error&amp;#34;; } } } 三个路由，view 解析 jsp，Upload 上传文件但是有黑名单，BackUp 打包 tar 和解包 tar，看下具体实现

黑盒打 Commons-Beanutils 1.9+ 自带 Commons-Collections3.2.1，高版本 jdk17，用sun.misc.Unsafe来反射。
