;/dependencies&amp;gt; &amp;lt;build&amp;gt; &amp;lt;plugins&amp;gt; &amp;lt;plugin&amp;gt; &amp;lt;groupId&amp;gt;org.apache.maven.plugins&amp;lt;/groupId&amp;gt; &amp;lt;artifactId&amp;gt;maven-compiler-plugin&amp;lt;/artifactId&amp;gt; &amp;lt;version&amp;gt;3.8.1&amp;lt;/version&amp;gt; &amp;lt;configuration&amp;gt; &amp;lt;source&amp;gt;17&amp;lt;/source&amp;gt; &amp;lt;target&amp;gt;17&amp;lt;/target&amp;gt; &amp;lt;encoding&amp;gt;UTF-8&amp;lt;/encoding&amp;gt; &amp;lt;compilerArgs&amp;gt; &amp;lt;arg&amp;gt;--add-exports=java.xml/com.sun.org.apache.xalan.internal.xsltc.runtime=ALL-UNNAMED&amp;lt;/arg&amp;gt; &amp;lt;arg&amp;gt;--add-exports=java.xml/com.sun.org.apache.xalan.internal.xsltc.trax=ALL-UNNAMED&amp;lt;/arg&amp;gt; &amp;lt;arg&amp;gt;--add-exports=java.xml/com.sun.org.apache.xalan.internal.xsltc=ALL-UNNAMED&amp;lt;/arg&amp;gt; &amp;lt;arg&amp;gt;--add-exports=java.xml/com.sun.org.apache.xml.internal.serializer=ALL-UNNAMED&amp;lt;/arg&amp;gt; &amp;lt;arg&amp;gt;--add-exports=java.xml/com.sun.org.apache.xml.internal.dtm=ALL-UNNAMED&amp;lt;/arg&amp;gt; &amp;lt;/compilerArgs&amp;gt; &amp;lt;/configuration&amp;gt; &amp;lt;/plugin&amp;gt; &amp;lt;/plugins&amp;gt; &amp;lt;/build&amp;gt; &amp;lt;/project&amp;gt;
